const { S3Client, GetObjectCommand, PutObjectCommand } = require('@aws-sdk/client-s3');
const path = require('path');
const crypto = require('crypto');

const s3Client = new S3Client({ region: process.env.AWS_REGION });

const ALLOWED_EXTENSIONS = ['.txt', '.pdf', '.doc', '.docx', '.csv', '.json', '.xml'];
const MAX_FILE_SIZE = 100 * 1024 * 1024; // 100MB
const OUTPUT_BUCKET = process.env.OUTPUT_BUCKET;

function sanitizeFilename(filename) {
  // Remove any path traversal attempts
  const basename = path.basename(filename);
  
  // Remove or replace dangerous characters
  const sanitized = basename.replace(/[^a-zA-Z0-9._-]/g, '_');
  
  // Prevent hidden files and ensure reasonable length
  const cleaned = sanitized.replace(/^\.+/, '').substring(0, 255);
  
  if (!cleaned || cleaned.length === 0) {
    return `file_${crypto.randomUUID()}`;
  }
  
  return cleaned;
}

function validateFileExtension(filename) {
  const ext = path.extname(filename).toLowerCase();
  return ALLOWED_EXTENSIONS.includes(ext);
}

async function streamToBuffer(stream) {
  return new Promise((resolve, reject) => {
    const chunks = [];
    let totalSize = 0;
    
    stream.on('data', (chunk) => {
      totalSize += chunk.length;
      if (totalSize > MAX_FILE_SIZE) {
        stream.destroy();
        reject(new Error('File size exceeds maximum allowed size'));
        return;
      }
      chunks.push(chunk);
    });
    
    stream.on('error', reject);
    stream.on('end', () => resolve(Buffer.concat(chunks)));
  });
}

async function processFile(buffer, filename) {
  // Example processing: convert to uppercase for text files
  // Replace with actual document processing logic
  const ext = path.extname(filename).toLowerCase();
  
  if (ext === '.txt' || ext === '.csv') {
    const content = buffer.toString('utf-8');
    const processed = content.toUpperCase();
    return Buffer.from(processed, 'utf-8');
  }
  
  // For other file types, return as-is (implement actual processing)
  return buffer;
}

exports.handler = async (event) => {
  const results = [];
  
  for (const record of event.Records) {
    try {
      if (record.eventName.startsWith('ObjectRemoved')) {
        console.log('Skipping delete event');
        continue;
      }
      
      const sourceBucket = record.s3.bucket.name;
      const sourceKey = decodeURIComponent(record.s3.object.key.replace(/\+/g, ' '));
      
      // Validate bucket name to prevent SSRF
      if (!sourceBucket.match(/^[a-z0-9][a-z0-9.-]*[a-z0-9]$/)) {
        throw new Error('Invalid bucket name');
      }
      
      // Extract filename from key
      const originalFilename = path.basename(sourceKey);
      
      // Validate file extension
      if (!validateFileExtension(originalFilename)) {
        throw new Error(`File extension not allowed: ${originalFilename}`);
      }
      
      // Sanitize filename for output
      const sanitizedFilename = sanitizeFilename(originalFilename);
      const outputKey = `processed/${sanitizedFilename}`;
      
      console.log(`Processing file: ${sourceKey} -> ${outputKey}`);
      
      // Get file from S3
      const getCommand = new GetObjectCommand({
        Bucket: sourceBucket,
        Key: sourceKey
      });
      
      const response = await s3Client.send(getCommand);
      
      // Validate content type
      const contentType = response.ContentType || '';
      const allowedContentTypes = [
        'text/plain',
        'application/pdf',
        'application/msword',
        'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
        'text/csv',
        'application/json',
        'application/xml',
        'text/xml'
      ];
      
      if (!allowedContentTypes.some(type => contentType.startsWith(type))) {
        console.warn(`Warning: Unexpected content type: ${contentType}`);
      }
      
      // Read file content with size limit
      const fileBuffer = await streamToBuffer(response.Body);
      
      // Process the file
      const processedBuffer = await processFile(fileBuffer, sanitizedFilename);
      
      // Validate output bucket
      if (!OUTPUT_BUCKET || !OUTPUT_BUCKET.match(/^[a-z0-9][a-z0-9.-]*[a-z0-9]$/)) {
        throw new Error('Invalid output bucket configuration');
      }
      
      // Save to output bucket
      const putCommand = new PutObjectCommand({
        Bucket: OUTPUT_BUCKET,
        Key: outputKey,
        Body: processedBuffer,
        ContentType: response.ContentType,
        ServerSideEncryption: 'AES256',
        Metadata: {
          'original-filename': sanitizedFilename,
          'processed-date': new Date().toISOString(),
          'source-bucket': sourceBucket
        }
      });
      
      await s3Client.send(putCommand);
      
      results.push({
        status: 'success',
        sourceKey,
        outputKey,
        size: processedBuffer.length
      });
      
      console.log(`Successfully processed: ${sourceKey}`);
      
    } catch (error) {
      console.error(`Error processing file:`, error);
      results.push({
        status: 'error',
        sourceKey: record.s3.object.key,
        error: error.message
      });
    }
  }
  
  return {
    statusCode: 200,
    body: JSON.stringify({
      message: 'Processing complete',
      results
    })
  };
};